mapper.select:
SELECT r.id, r.borrow_id, r.equipment_id, r.equipment_number, r.equipment_name, COALESCE(r.equipment_model, e.equipment_model) AS equipment_model, COALESCE(r.equipment_image, e.equipment_image) AS equipment_image, r.equipment_type_id, et.type_name AS equipment_type, r.user_id, u.real_name AS real_name, u.phone AS phone, r.purpose, r.return_quantity, b.borrow_quantity + COALESCE((SELECT SUM(er.return_quantity) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1), 0) AS original_borrow_quantity, b.borrow_quantity, r.repair_quantity, r.return_time, r.expected_return_time, r.actual_return_time, r.return_status, r.audit_status, r.audit_user_id, au.real_name AS audit_user_name, r.audit_time, r.audit_result, r.create_time, r.update_time FROM equipment_return r LEFT JOIN equipment e ON r.equipment_id = e.id LEFT JOIN equipment_type et ON e.equipment_type_id = et.id LEFT JOIN sys_user u ON r.user_id = u.id LEFT JOIN sys_user au ON r.audit_user_id = au.id LEFT JOIN equipment_borrow b ON r.borrow_id = b.id
AND r.user_id = #{userId}
AND r.return_status = #{status}
AND r.audit_status = #{auditStatus}
AND (r.equipment_name LIKE CONCAT('%', #{keyword}, '%') OR r.equipment_number LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.create_time DESC

SELECT COUNT(*) 
FROM equipment_return 
WHERE user_id = #{userId} 
AND equipment_id = #{equipmentId}
AND audit_status = 0

SELECT r.id, r.borrow_id, r.equipment_id, r.equipment_number, r.equipment_name, r.equipment_model, r.equipment_image, r.equipment_type_id, et.type_name AS equipment_type, r.user_id, u.real_name AS real_name, u.phone AS phone, r.return_status, r.purpose, r.return_quantity, r.expected_return_time, r.actual_return_time, r.repair_quantity, r.return_time, r.audit_status, r.audit_result, r.audit_user_id, au.real_name AS audit_user_name, r.audit_time, r.create_time, r.update_time FROM equipment_return r LEFT JOIN equipment e ON r.equipment_id = e.id LEFT JOIN equipment_type et ON e.equipment_type_id = et.id LEFT JOIN sys_user u ON r.user_id = u.id LEFT JOIN sys_user au ON r.audit_user_id = au.id
AND r.equipment_id IN
#{id}
AND r.user_id = #{userId}
AND r.create_time >= #{startTime}
ORDER BY r.create_time DESC LIMIT 1000
